{
  "name": "IntraHelp - Sistema de Chamados Internos",
  "description": "Uma plataforma de intranet para gerenciamento de chamados técnicos, permitindo abertura, acompanhamento e administração de solicitações internas."
}

export enum UserRole {
  ADMIN = 'Administrador',
  USER = 'Usuário Comum'
}

export enum TicketStatus {
  OPEN = 'Em aberto',
  ANALYSIS = 'Em análise',
  WAITING = 'Em espera',
  CLOSED = 'Encerrado'
}

export interface HistoryEntry {
  id: string;
  timestamp: string;
  userName: string;
  action: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  password?: string;
  role: UserRole;
}

export interface Ticket {
  id: string;
  requesterId: string;
  requesterName: string;
  sector: string;
  extension: string;
  description: string;
  status: TicketStatus;
  createdAt: string;
  history: HistoryEntry[];
  adminResponse?: string;
}

export type AuthState = {
  user: User | null;
  isAuthenticated: boolean;
};

import { User, Ticket, UserRole } from '../types';

const USERS_KEY = 'intrahelp_users';
const TICKETS_KEY = 'intrahelp_tickets';
const SESSION_KEY = 'intrahelp_session';

export const storage = {
  getUsers: (): User[] => {
    const data = localStorage.getItem(USERS_KEY);
    if (!data) {
      // Seed default admin
      const defaultAdmin: User = {
        id: 'admin-id',
        name: 'Administrador Sistema',
        email: 'admin',
        password: 'admin',
        role: UserRole.ADMIN
      };
      localStorage.setItem(USERS_KEY, JSON.stringify([defaultAdmin]));
      return [defaultAdmin];
    }
    return JSON.parse(data);
  },

  saveUsers: (users: User[]) => {
    localStorage.setItem(USERS_KEY, JSON.stringify(users));
  },

  getTickets: (): Ticket[] => {
    const data = localStorage.getItem(TICKETS_KEY);
    return data ? JSON.parse(data) : [];
  },

  saveTickets: (tickets: Ticket[]) => {
    localStorage.setItem(TICKETS_KEY, JSON.stringify(tickets));
  },

  getCurrentSession: (): User | null => {
    const data = localStorage.getItem(SESSION_KEY);
    return data ? JSON.parse(data) : null;
  },

  setSession: (user: User | null) => {
    if (user) {
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }
};

import React from 'react';
import { User, UserRole } from '../types';

interface LayoutProps {
  user: User;
  onLogout: () => void;
  onNavigate: (page: string) => void;
  currentPage: string;
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ user, onLogout, onNavigate, currentPage, children }) => {
  const isAdmin = user.role === UserRole.ADMIN;

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0">
        <div className="p-6">
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <i className="fas fa-headset text-blue-400"></i>
            IntraHelp
          </h1>
          <p className="text-slate-400 text-xs mt-1 uppercase tracking-widest font-semibold">Intranet Corporativa</p>
        </div>

        <nav className="mt-6 px-4 space-y-2">
          <button
            onClick={() => onNavigate('dashboard')}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
              currentPage === 'dashboard' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'
            }`}
          >
            <i className="fas fa-list-check"></i>
            Chamados
          </button>

          {isAdmin && (
            <button
              onClick={() => onNavigate('users')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                currentPage === 'users' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'
              }`}
            >
              <i className="fas fa-users-cog"></i>
              Permissões
            </button>
          )}
        </nav>

        <div className="mt-auto p-4 border-t border-slate-800 mt-20">
          <div className="flex items-center gap-3 mb-4 px-2">
            <div className="w-10 h-10 rounded-full bg-blue-500 flex items-center justify-center font-bold">
              {user.name.charAt(0)}
            </div>
            <div className="overflow-hidden">
              <p className="text-sm font-medium truncate">{user.name}</p>
              <p className="text-xs text-slate-400 truncate">{user.role}</p>
            </div>
          </div>
          <button
            onClick={onLogout}
            className="w-full flex items-center gap-3 px-4 py-2 text-red-400 hover:bg-red-900/20 rounded-lg transition-colors"
          >
            <i className="fas fa-sign-out-alt"></i>
            Sair
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-grow bg-slate-50 p-6 md:p-10 overflow-y-auto max-h-screen">
        {children}
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useCallback } from 'react';
import { User, Ticket, UserRole, AuthState, TicketStatus, HistoryEntry } from './types';
import { storage } from './services/storage';
import LoginForm from './components/Auth/LoginForm';
import RegisterForm from './components/Auth/RegisterForm';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import UserManagement from './components/UserManagement';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [view, setView] = useState<'login' | 'register' | 'dashboard' | 'users'>('login');
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [users, setUsers] = useState<User[]>([]);

  // Initialize
  useEffect(() => {
    const session = storage.getCurrentSession();
    if (session) {
      setAuth({ user: session, isAuthenticated: true });
      setView('dashboard');
    }
    setTickets(storage.getTickets());
    setUsers(storage.getUsers());
  }, []);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
    storage.setSession(user);
    setView('dashboard');
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    storage.setSession(null);
    setView('login');
  };

  const updateTickets = (newTickets: Ticket[]) => {
    setTickets(newTickets);
    storage.saveTickets(newTickets);
  };

  const updateUsers = (newUsers: User[]) => {
    setUsers(newUsers);
    storage.saveUsers(newUsers);
  };

  const handleCreateTicket = (ticketData: Partial<Ticket>) => {
    if (!auth.user) return;
    const newTicket: Ticket = {
      id: `TK-${Date.now()}`,
      requesterId: auth.user.id,
      requesterName: ticketData.requesterName || auth.user.name,
      sector: ticketData.sector || '',
      extension: ticketData.extension || '',
      description: ticketData.description || '',
      status: TicketStatus.OPEN,
      createdAt: new Date().toISOString(),
      history: [{
        id: `HIST-${Date.now()}`,
        timestamp: new Date().toISOString(),
        userName: auth.user.name,
        action: 'Abertura do chamado'
      }]
    };
    updateTickets([newTicket, ...tickets]);
  };

  const handleUpdateTicket = (ticketId: string, updates: Partial<Ticket>) => {
    if (!auth.user) return;

    const updatedTickets = tickets.map(t => {
      if (t.id === ticketId) {
        const historyEntry: HistoryEntry = {
          id: `HIST-${Date.now()}`,
          timestamp: new Date().toISOString(),
          userName: auth.user!.name,
          action: updates.status ? `Status alterado para ${updates.status}` : 'Informações atualizadas'
        };
        return {
          ...t,
          ...updates,
          history: [...t.history, historyEntry]
        };
      }
      return t;
    });
    updateTickets(updatedTickets);
  };

  if (!auth.isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center p-4">
        {view === 'login' ? (
          <LoginForm 
            onLogin={handleLogin} 
            onSwitchToRegister={() => setView('register')} 
          />
        ) : (
          <RegisterForm 
            onRegisterSuccess={() => setView('login')} 
            onSwitchToLogin={() => setView('login')} 
          />
        )}
      </div>
    );
  }

  return (
    <Layout 
      user={auth.user!} 
      onLogout={handleLogout} 
      onNavigate={(page) => setView(page as any)}
      currentPage={view}
    >
      {view === 'dashboard' && (
        <Dashboard 
          user={auth.user!} 
          tickets={tickets} 
          onAddTicket={handleCreateTicket}
          onUpdateTicket={handleUpdateTicket}
        />
      )}
      {view === 'users' && auth.user?.role === UserRole.ADMIN && (
        <UserManagement 
          users={users} 
          onUpdateUsers={updateUsers} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { storage } from '../../services/storage';
import { User } from '../../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  onSwitchToRegister: () => void;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, onSwitchToRegister }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const users = storage.getUsers();
    const user = users.find(u => u.email === email && u.password === password);

    if (user) {
      onLogin(user);
    } else {
      setError('Credenciais inválidas. Use "admin" / "admin" para acesso inicial.');
    }
  };

  const handleForgotPassword = () => {
    alert('Simulação: Um link de redefinição de senha foi enviado para seu e-mail corporativo.');
  };

  return (
    <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-200">
      <div className="flex flex-col items-center mb-8">
        <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white text-3xl mb-4 shadow-lg shadow-blue-200">
          <i className="fas fa-headset"></i>
        </div>
        <h2 className="text-2xl font-bold text-slate-800">IntraHelp Login</h2>
        <p className="text-slate-500">Acesse o portal de suporte interno</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        {error && (
          <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm flex items-center gap-2">
            <i className="fas fa-exclamation-circle"></i>
            {error}
          </div>
        )}

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Usuário / E-mail</label>
          <input
            type="text"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
            placeholder="Seu usuário"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Senha</label>
          <input
            type="password"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
        </div>

        <div className="flex items-center justify-between py-2">
          <label className="flex items-center gap-2 cursor-pointer group">
            <input type="checkbox" className="w-4 h-4 rounded text-blue-600 border-slate-300 focus:ring-blue-500" />
            <span className="text-sm text-slate-600 group-hover:text-slate-800 transition-colors">Manter-me conectado</span>
          </label>
          <button 
            type="button" 
            onClick={handleForgotPassword}
            className="text-sm text-blue-600 hover:text-blue-800 font-medium"
          >
            Esqueci minha senha
          </button>
        </div>

        <button
          type="submit"
          className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-lg shadow-lg shadow-blue-200 transition-all transform hover:-translate-y-0.5"
        >
          Entrar no Sistema
        </button>
      </form>

      <div className="mt-8 pt-6 border-t border-slate-100 text-center">
        <p className="text-slate-600">
          Não possui acesso? 
          <button 
            onClick={onSwitchToRegister}
            className="ml-2 text-blue-600 hover:text-blue-800 font-bold"
          >
            Faça seu cadastro
          </button>
        </p>
      </div>
    </div>
  );
};

export default LoginForm;

import React, { useState } from 'react';
import { storage } from '../../services/storage';
import { User, UserRole } from '../../types';

interface RegisterFormProps {
  onRegisterSuccess: () => void;
  onSwitchToLogin: () => void;
}

const RegisterForm: React.FC<RegisterFormProps> = ({ onRegisterSuccess, onSwitchToLogin }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (formData.password !== formData.confirmPassword) {
      setError('As senhas não coincidem.');
      return;
    }

    const users = storage.getUsers();
    if (users.some(u => u.email === formData.email)) {
      setError('Este usuário já existe no sistema.');
      return;
    }

    const newUser: User = {
      id: `USR-${Date.now()}`,
      name: formData.name,
      email: formData.email,
      password: formData.password,
      role: UserRole.USER
    };

    storage.saveUsers([...users, newUser]);
    alert('Cadastro realizado com sucesso! Você já pode entrar.');
    onRegisterSuccess();
  };

  return (
    <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-200">
      <h2 className="text-2xl font-bold text-slate-800 mb-2">Novo Cadastro</h2>
      <p className="text-slate-500 mb-6">Crie sua conta corporativa para abrir chamados</p>

      <form onSubmit={handleSubmit} className="space-y-4">
        {error && (
          <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm">
            {error}
          </div>
        )}

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo</label>
          <input
            type="text"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 outline-none focus:ring-2 focus:ring-blue-500"
            value={formData.name}
            onChange={(e) => setFormData({ ...formData, name: e.target.value })}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">E-mail Corporativo / Usuário</label>
          <input
            type="text"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 outline-none focus:ring-2 focus:ring-blue-500"
            value={formData.email}
            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Senha</label>
          <input
            type="password"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 outline-none focus:ring-2 focus:ring-blue-500"
            value={formData.password}
            onChange={(e) => setFormData({ ...formData, password: e.target.value })}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Confirmar Senha</label>
          <input
            type="password"
            required
            className="w-full px-4 py-3 rounded-lg border border-slate-300 outline-none focus:ring-2 focus:ring-blue-500"
            value={formData.confirmPassword}
            onChange={(e) => setFormData({ ...formData, confirmPassword: e.target.value })}
          />
        </div>

        <button
          type="submit"
          className="w-full py-3 bg-slate-900 hover:bg-slate-800 text-white font-bold rounded-lg shadow-lg transition-all"
        >
          Finalizar Cadastro
        </button>
      </form>

      <div className="mt-6 text-center">
        <button 
          onClick={onSwitchToLogin}
          className="text-sm text-slate-600 hover:text-blue-600 transition-colors"
        >
          Já tenho uma conta. Voltar ao login.
        </button>
      </div>
    </div>
  );
};

export default RegisterForm;

import React, { useState } from 'react';
import { User, Ticket, UserRole, TicketStatus } from '../types';
import TicketModal from './TicketModal';

interface DashboardProps {
  user: User;
  tickets: Ticket[];
  onAddTicket: (ticket: Partial<Ticket>) => void;
  onUpdateTicket: (ticketId: string, updates: Partial<Ticket>) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, tickets, onAddTicket, onUpdateTicket }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTicket, setEditingTicket] = useState<Ticket | null>(null);

  const isAdmin = user.role === UserRole.ADMIN;

  // Filter tickets: Admins see all (maybe default open), Users see their own
  const filteredTickets = isAdmin 
    ? tickets 
    : tickets.filter(t => t.requesterId === user.id);

  const stats = {
    total: filteredTickets.length,
    open: filteredTickets.filter(t => t.status === TicketStatus.OPEN).length,
    waiting: filteredTickets.filter(t => t.status === TicketStatus.WAITING).length,
    closed: filteredTickets.filter(t => t.status === TicketStatus.CLOSED).length,
  };

  const openNewTicket = () => {
    setEditingTicket(null);
    setIsModalOpen(true);
  };

  const editTicket = (ticket: Ticket) => {
    setEditingTicket(ticket);
    setIsModalOpen(true);
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900">Gerenciamento de Chamados</h2>
          <p className="text-slate-500">Visualize e gerencie suas solicitações internas</p>
        </div>
        <button
          onClick={openNewTicket}
          className="flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg shadow-blue-200 transition-all transform hover:scale-105 active:scale-95"
        >
          <i className="fas fa-plus"></i>
          Novo Chamado
        </button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Total" count={stats.total} icon="fa-folder" color="bg-slate-100 text-slate-600" />
        <StatCard label="Em Aberto" count={stats.open} icon="fa-envelope-open" color="bg-red-50 text-red-600" />
        <StatCard label="Em Espera" count={stats.waiting} icon="fa-clock" color="bg-amber-50 text-amber-600" />
        <StatCard label="Encerrados" count={stats.closed} icon="fa-check-double" color="bg-emerald-50 text-emerald-600" />
      </div>

      {/* Ticket List */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">ID / Data</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Solicitante</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Assunto</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTickets.length > 0 ? (
                filteredTickets.map(ticket => (
                  <tr key={ticket.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-bold text-slate-900">{ticket.id}</div>
                      <div className="text-xs text-slate-500">{new Date(ticket.createdAt).toLocaleDateString()}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-slate-900 font-medium">{ticket.requesterName}</div>
                      <div className="text-xs text-slate-500">{ticket.sector}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-slate-900 truncate max-w-xs">{ticket.description}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <StatusBadge status={ticket.status} />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <button
                        onClick={() => editTicket(ticket)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                      >
                        <i className="fas fa-pencil-alt"></i>
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                    <i className="fas fa-inbox text-4xl mb-3 opacity-20"></i>
                    <p>Nenhum chamado encontrado.</p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <TicketModal 
          user={user}
          ticket={editingTicket}
          onClose={() => setIsModalOpen(false)}
          onSave={(data) => {
            if (editingTicket) {
              onUpdateTicket(editingTicket.id, data);
            } else {
              onAddTicket(data);
            }
            setIsModalOpen(false);
          }}
        />
      )}
    </div>
  );
};

const StatCard = ({ label, count, icon, color }: any) => (
  <div className={`p-4 rounded-2xl flex items-center gap-4 ${color}`}>
    <div className="text-2xl w-12 h-12 flex items-center justify-center rounded-xl bg-white/50">
      <i className={`fas ${icon}`}></i>
    </div>
    <div>
      <p className="text-xs font-bold uppercase opacity-70 leading-tight">{label}</p>
      <p className="text-2xl font-black">{count}</p>
    </div>
  </div>
);

const StatusBadge = ({ status }: { status: TicketStatus }) => {
  const colors = {
    [TicketStatus.OPEN]: 'bg-blue-100 text-blue-700',
    [TicketStatus.ANALYSIS]: 'bg-purple-100 text-purple-700',
    [TicketStatus.WAITING]: 'bg-amber-100 text-amber-700',
    [TicketStatus.CLOSED]: 'bg-emerald-100 text-emerald-700',
  };
  return (
    <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${colors[status]}`}>
      {status}
    </span>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { User, Ticket, UserRole, TicketStatus } from '../types';

interface TicketModalProps {
  user: User;
  ticket: Ticket | null;
  onClose: () => void;
  onSave: (data: any) => void;
}

const TicketModal: React.FC<TicketModalProps> = ({ user, ticket, onClose, onSave }) => {
