                    type="text"
                    required
                    readOnly={isEditing && !isAdmin}
                    className={`w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500 ${isEditing && !isAdmin ? 'bg-slate-50' : ''}`}
                    value={formData.sector}
                    onChange={(e) => setFormData({ ...formData, sector: e.target.value })}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-600 mb-1">Ramal</label>
                  <input
                    type="text"
                    required
                    readOnly={isEditing && !isAdmin}
                    className={`w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500 ${isEditing && !isAdmin ? 'bg-slate-50' : ''}`}
                    value={formData.extension}
