export default TicketModal;

import React from 'react';
import { User, UserRole } from '../types';

interface UserManagementProps {
  users: User[];
  onUpdateUsers: (users: User[]) => void;
}

const UserManagement: React.FC<UserManagementProps> = ({ users, onUpdateUsers }) => {
  const toggleRole = (userId: string) => {
    const updatedUsers = users.map(u => {
      if (u.id === userId) {
        // Prevent accidental lockout of all admins (simple check)
        if (u.email === 'admin' && u.role === UserRole.ADMIN) {
          alert('Não é possível remover o nível do administrador principal.');
          return u;
        }
        return {
          ...u,
          role: u.role === UserRole.ADMIN ? UserRole.USER : UserRole.ADMIN
        };
      }
      return u;
    });
    onUpdateUsers(updatedUsers);
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-3xl font-extrabold text-slate-900">Controle de Permissões</h2>
        <p className="text-slate-500">Defina os níveis de acesso dos colaboradores</p>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Usuário</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">E-mail / Login</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Nível de Acesso</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Ação</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {users.map(user => (
              <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-600 text-xs">
                      {user.name.charAt(0)}
                    </div>
                    <span className="text-sm font-bold text-slate-900">{user.name}</span>
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                  {user.email}
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${
                    user.role === UserRole.ADMIN ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-600'
                  }`}>
                    {user.role}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <button
                    onClick={() => toggleRole(user.id)}
                    className={`px-4 py-1 rounded-lg text-xs font-bold transition-all ${
                      user.role === UserRole.ADMIN 
                        ? 'text-slate-500 hover:bg-slate-200' 
                        : 'text-blue-600 hover:bg-blue-50'
                    }`}
                  >
                    {user.role === UserRole.ADMIN ? 'Tornar Usuário Comum' : 'Promover a Admin'}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100">
        <h4 className="text-blue-900 font-bold mb-2 flex items-center gap-2">
          <i className="fas fa-shield-alt"></i>
          Nota sobre Permissões
        </h4>
        <p className="text-sm text-blue-800 leading-relaxed">
          Administradores têm permissão para visualizar todos os chamados da empresa, alterar o status das solicitações e responder tecnicamente.
          Usuários comuns visualizam apenas seus próprios chamados e podem editá-los enquanto estiverem em aberto.
        </p>
      </div>
    </div>
  );
};

