import React, { useState } from 'react';
import { User, Ticket, UserRole, TicketStatus } from '../types';
import TicketModal from './TicketModal';
import ReportModal from './ReportModal';

interface DashboardProps {
  user: User;
  tickets: Ticket[];
  onAddTicket: (ticket: Partial<Ticket>) => void;
  onUpdateTicket: (ticketId: string, updates: Partial<Ticket>) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, tickets, onAddTicket, onUpdateTicket }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isReportOpen, setIsReportOpen] = useState(false);
  const [editingTicket, setEditingTicket] = useState<Ticket | null>(null);

  const isAdmin = user.role === UserRole.ADMIN;

  const filteredTickets = isAdmin 
    ? tickets 
    : tickets.filter(t => t.requesterId === user.id);

  const stats = {
    total: filteredTickets.length,
    open: filteredTickets.filter(t => t.status === TicketStatus.OPEN).length,
    analysis: filteredTickets.filter(t => t.status === TicketStatus.ANALYSIS).length,
    waiting: filteredTickets.filter(t => t.status === TicketStatus.WAITING).length,
    closed: filteredTickets.filter(t => t.status === TicketStatus.CLOSED).length,
  };

  const openNewTicket = () => {
    setEditingTicket(null);
    setIsModalOpen(true);
  };

  const editTicket = (ticket: Ticket) => {
    setEditingTicket(ticket);
    setIsModalOpen(true);
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900">Gerenciamento de Chamados</h2>
          <p className="text-slate-500">Visualize e gerencie suas solicitações internas</p>
        </div>
        <div className="flex gap-3">
          {isAdmin && (
            <button
              onClick={() => setIsReportOpen(true)}
              className="flex items-center justify-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 font-bold rounded-xl shadow-sm transition-all"
            >
              <i className="fas fa-file-alt"></i>
              Relatório
            </button>
          )}
          <button
            onClick={openNewTicket}
            className="flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-lg shadow-blue-200 transition-all transform hover:scale-105 active:scale-95"
          >
            <i className="fas fa-plus"></i>
            Novo Chamado
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
        <StatCard label="Total" count={stats.total} icon="fa-folder" color="bg-slate-100 text-slate-600" />
        <StatCard label="Em Aberto" count={stats.open} icon="fa-envelope-open" color="bg-red-50 text-red-600" />
        <StatCard label="Em Análise" count={stats.analysis} icon="fa-search" color="bg-purple-50 text-purple-600" />
        <StatCard label="Em Espera" count={stats.waiting} icon="fa-clock" color="bg-amber-50 text-amber-600" />
        <StatCard label="Encerrados" count={stats.closed} icon="fa-check-double" color="bg-emerald-50 text-emerald-600" />
      </div>

      {/* Ticket List */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">ID / Data</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Solicitante</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Assunto</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTickets.length > 0 ? (
                filteredTickets.map(ticket => (
                  <tr key={ticket.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-bold text-slate-900">{ticket.id}</div>
                      <div className="text-xs text-slate-500">{new Date(ticket.createdAt).toLocaleDateString()}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-slate-900 font-medium">{ticket.requesterName}</div>
                      <div className="text-xs text-slate-500">{ticket.sector}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-slate-900 truncate max-w-xs">{ticket.description}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <StatusBadge status={ticket.status} />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <button
                        onClick={() => editTicket(ticket)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                      >
                        <i className="fas fa-pencil-alt"></i>
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-slate-500">
                    <i className="fas fa-inbox text-4xl mb-3 opacity-20"></i>
                    <p>Nenhum chamado encontrado.</p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <TicketModal 
          user={user}
          ticket={editingTicket}
          onClose={() => setIsModalOpen(false)}
          onSave={(data) => {
            if (editingTicket) {
              onUpdateTicket(editingTicket.id, data);
            } else {
              onAddTicket(data);
            }
            setIsModalOpen(false);
          }}
        />
      )}

      {isReportOpen && (
        <ReportModal 
          tickets={tickets} 
          onClose={() => setIsReportOpen(false)} 
        />
      )}
    </div>
  );
};

const StatCard = ({ label, count, icon, color }: any) => (
  <div className={`p-4 rounded-2xl flex items-center gap-4 ${color}`}>
    <div className="text-2xl w-10 h-10 flex items-center justify-center rounded-xl bg-white/50">
      <i className={`fas ${icon} text-lg`}></i>
    </div>
    <div>
      <p className="text-[10px] font-bold uppercase opacity-70 leading-tight">{label}</p>
      <p className="text-xl font-black">{count}</p>
    </div>
  </div>
);

const StatusBadge = ({ status }: { status: TicketStatus }) => {
  const colors = {
    [TicketStatus.OPEN]: 'bg-blue-100 text-blue-700',
    [TicketStatus.ANALYSIS]: 'bg-purple-100 text-purple-700',
    [TicketStatus.WAITING]: 'bg-amber-100 text-amber-700',
    [TicketStatus.CLOSED]: 'bg-emerald-100 text-emerald-700',
  };
  return (
    <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${colors[status]}`}>
      {status}
    </span>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Ticket, TicketStatus } from '../types';

interface ReportModalProps {
  tickets: Ticket[];
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ tickets, onClose }) => {
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [hasGenerated, setHasGenerated] = useState(false);

  const reportData = useMemo(() => {
    if (!startDate || !endDate) return null;

    const start = new Date(startDate);
    start.setHours(0, 0, 0, 0);
    const end = new Date(endDate);
    end.setHours(23, 59, 59, 999);

    const filtered = tickets.filter(t => {
      const created = new Date(t.createdAt);
      return created >= start && created <= end;
    });

    const breakdown = {
      [TicketStatus.OPEN]: filtered.filter(t => t.status === TicketStatus.OPEN).length,
      [TicketStatus.ANALYSIS]: filtered.filter(t => t.status === TicketStatus.ANALYSIS).length,
      [TicketStatus.WAITING]: filtered.filter(t => t.status === TicketStatus.WAITING).length,
      [TicketStatus.CLOSED]: filtered.filter(t => t.status === TicketStatus.CLOSED).length,
    };

    return {
      total: filtered.length,
      breakdown
    };
  }, [tickets, startDate, endDate]);

  const handleGenerate = (e: React.FormEvent) => {
    e.preventDefault();
    setHasGenerated(true);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
      <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden flex flex-col">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
          <h3 className="text-xl font-bold text-slate-800">Extrair Relatório</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-6 space-y-6">
          <form onSubmit={handleGenerate} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Inicial</label>
                <input
                  type="date"
                  required
                  className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                  value={startDate}
                  onChange={(e) => {
                    setStartDate(e.target.value);
                    setHasGenerated(false);
                  }}
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Data Final</label>
                <input
                  type="date"
                  required
                  className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500"
                  value={endDate}
                  onChange={(e) => {
                    setEndDate(e.target.value);
                    setHasGenerated(false);
                  }}
                />
              </div>
            </div>
            <button
              type="submit"
              className="w-full py-2 bg-slate-900 text-white font-bold rounded-lg hover:bg-slate-800 transition-colors"
            >
              Gerar Relatório
            </button>
          </form>

          {hasGenerated && reportData && (
            <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="p-4 bg-blue-50 rounded-2xl text-center">
                <p className="text-sm text-blue-600 font-bold uppercase">Total no Período</p>
                <p className="text-4xl font-black text-blue-900">{reportData.total}</p>
              </div>

              <div className="space-y-2">
                <ReportRow label="Em Aberto" count={reportData.breakdown[TicketStatus.OPEN]} color="text-red-600" />
                <ReportRow label="Em Análise" count={reportData.breakdown[TicketStatus.ANALYSIS]} color="text-purple-600" />
                <ReportRow label="Em Espera" count={reportData.breakdown[TicketStatus.WAITING]} color="text-amber-600" />
                <ReportRow label="Encerrados" count={reportData.breakdown[TicketStatus.CLOSED]} color="text-emerald-600" />
              </div>

              <button
                onClick={() => window.print()}
                className="w-full text-xs text-slate-400 hover:text-slate-600 underline text-center block mt-4"
              >
                <i className="fas fa-print mr-1"></i> Imprimir ou salvar PDF
              </button>
            </div>
