import React, { useState, useMemo } from 'react';
import { Ticket, TicketStatus } from '../types';

interface ReportModalProps {
  tickets: Ticket[];
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ tickets, onClose }) => {
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [hasGenerated, setHasGenerated] = useState(false);

  const reportData = useMemo(() => {
    if (!startDate || !endDate) return null;

    const start = new Date(startDate);
    start.setHours(0, 0, 0, 0);
    const end = new Date(endDate);
    end.setHours(23, 59, 59, 999);

    const filtered = tickets.filter(t => {
      const created = new Date(t.createdAt);
      return created >= start && created <= end;
    });

    const breakdown = {
      [TicketStatus.OPEN]: filtered.filter(t => t.status === TicketStatus.OPEN).length,
      [TicketStatus.ANALYSIS]: filtered.filter(t => t.status === TicketStatus.ANALYSIS).length,
      [TicketStatus.WAITING]: filtered.filter(t => t.status === TicketStatus.WAITING).length,
      [TicketStatus.CLOSED]: filtered.filter(t => t.status === TicketStatus.CLOSED).length,
    };

    return {
      total: filtered.length,
      breakdown
    };
  }, [tickets, startDate, endDate]);

  const handleGenerate = (e: React.FormEvent) => {
    e.preventDefault();
    setHasGenerated(true);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
      <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden flex flex-col border border-slate-200">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
          <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <i className="fas fa-chart-pie text-blue-600"></i>
            Relatório Gerencial
          </h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-6 space-y-6">
          <form onSubmit={handleGenerate} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-black text-slate-900 uppercase mb-1">Início</label>
                <input
                  type="date"
                  required
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                  value={startDate}
                  onChange={(e) => {
                    setStartDate(e.target.value);
                    setHasGenerated(false);
                  }}
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-900 uppercase mb-1">Fim</label>
                <input
                  type="date"
                  required
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                  value={endDate}
                  onChange={(e) => {
                    setEndDate(e.target.value);
                    setHasGenerated(false);
                  }}
                />
              </div>
            </div>
            <button
              type="submit"
              className="w-full py-3 bg-slate-900 text-white font-black rounded-xl hover:bg-slate-800 transition-all shadow-lg shadow-slate-200"
            >
              GERAR DADOS
            </button>
          </form>

          {hasGenerated && reportData && (
            <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="p-5 bg-slate-900 rounded-2xl text-center border-4 border-white shadow-xl">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Chamados Totais</p>
                <p className="text-5xl font-black text-white">{reportData.total}</p>
              </div>

              <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 space-y-2">
                <ReportRow label="Em Aberto" count={reportData.breakdown[TicketStatus.OPEN]} />
                <ReportRow label="Em Análise" count={reportData.breakdown[TicketStatus.ANALYSIS]} />
                <ReportRow label="Em Espera" count={reportData.breakdown[TicketStatus.WAITING]} />
                <ReportRow label="Encerrados" count={reportData.breakdown[TicketStatus.CLOSED]} />
              </div>

              <div className="flex gap-2">
                <button
                  onClick={() => window.print()}
                  className="flex-grow py-2 bg-white border border-slate-300 text-slate-900 font-bold rounded-lg text-xs hover:bg-slate-50 transition-all"
                >
                  <i className="fas fa-print mr-2"></i>Imprimir PDF
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const ReportRow = ({ label, count }: { label: string, count: number }) => (
  <div className="flex items-center justify-between p-2 border-b border-slate-200 last:border-0">
    <span className="text-xs font-black text-slate-900 uppercase bg-white px-2 py-1 border border-slate-200 rounded">{label}</span>
    <span className="font-black text-slate-900 text-lg">{count}</span>
  </div>
);

