                      onChange={(e) => setFormData({ ...formData, adminResponse: e.target.value })}
                    ></textarea>
                  </div>
                </>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-center p-8 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-200 text-slate-400">
                  <i className="fas fa-info-circle text-4xl mb-2"></i>
                  <p className="text-xs font-bold uppercase">Preencha os campos ao lado</p>
                  <p className="text-[10px]">O chamado será iniciado com status "Em aberto"</p>
                </div>
              )}
            </div>
          </form>
        </div>

        {/* Modal Footer */}
        <div className="p-6 border-t border-slate-100 flex items-center justify-end gap-3 bg-slate-50">
          <button
            onClick={onClose}
            className="px-6 py-2 text-slate-600 font-bold hover:text-slate-900 transition-all text-xs uppercase"
          >
            Fechar
          </button>
          <button
            form="ticket-form"
            type="submit"
            className="px-8 py-2 bg-slate-900 text-white font-black rounded-xl shadow-lg transition-all text-xs uppercase hover:bg-slate-800"
          >
            {isEditing ? 'Atualizar Chamado' : 'Salvar Chamado'}
          </button>
        </div>
      </div>
    </div>
  );
};

