import React, { useState, useEffect } from 'react';
import { User, Ticket, UserRole, TicketStatus } from '../types';

interface TicketModalProps {
  user: User;
  ticket: Ticket | null;
  onClose: () => void;
  onSave: (data: any) => void;
}

const TicketModal: React.FC<TicketModalProps> = ({ user, ticket, onClose, onSave }) => {
  const isAdmin = user.role === UserRole.ADMIN;
  const isEditing = !!ticket;

  const [formData, setFormData] = useState({
    requesterName: ticket?.requesterName || user.name,
    sector: ticket?.sector || '',
    extension: ticket?.extension || '',
    description: ticket?.description || '',
    status: ticket?.status || TicketStatus.OPEN,
    adminResponse: ticket?.adminResponse || ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave(formData);
  };

  const statusColors = {
    [TicketStatus.OPEN]: 'bg-blue-600',
    [TicketStatus.ANALYSIS]: 'bg-purple-600',
    [TicketStatus.WAITING]: 'bg-amber-600',
    [TicketStatus.CLOSED]: 'bg-emerald-600',
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
      <div className="bg-white w-full max-w-4xl max-h-[90vh] rounded-3xl shadow-2xl overflow-hidden flex flex-col border border-slate-200">
        {/* Modal Header */}
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
          <div>
            <h3 className="text-2xl font-black text-slate-900 tracking-tight">
              {isEditing ? `Chamado #${ticket.id}` : 'Nova Solicitação'}
            </h3>
            {isEditing && (
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-1">
                Registrado em: {new Date(ticket.createdAt).toLocaleString('pt-BR')}
              </p>
            )}
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-900 transition-colors">
            <i className="fas fa-times text-2xl"></i>
          </button>
        </div>

        <div className="flex-grow overflow-y-auto">
          <form id="ticket-form" onSubmit={handleSubmit} className="p-8 grid grid-cols-1 md:grid-cols-2 gap-8">

            {/* Left Column: Basic Info */}
            <div className="space-y-5">
              <h4 className="font-black text-slate-900 flex items-center gap-2 uppercase text-[11px] tracking-widest border-b pb-3 mb-2">
                <i className="fas fa-file-invoice text-blue-600"></i>
                Detalhamento
              </h4>

              <div>
                <label className="block text-[11px] font-black text-black uppercase mb-1.5 ml-1">Solicitante</label>
                <input
                  type="text"
                  required
                  readOnly={isEditing && !isAdmin}
                  className={`w-full px-4 py-3 rounded-xl border-2 border-slate-100 bg-slate-50 text-black font-bold outline-none focus:ring-2 focus:ring-blue-500 ${isEditing && !isAdmin ? 'opacity-70' : ''}`}
                  value={formData.requesterName}
                  onChange={(e) => setFormData({ ...formData, requesterName: e.target.value })}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[11px] font-black text-black uppercase mb-1.5 ml-1">Setor</label>
                  <input
                    type="text"
                    required
                    readOnly={isEditing && !isAdmin}
                    className={`w-full px-4 py-3 rounded-xl border-2 border-slate-100 bg-slate-50 text-black font-bold outline-none focus:ring-2 focus:ring-blue-500 ${isEditing && !isAdmin ? 'opacity-70' : ''}`}
                    value={formData.sector}
                    onChange={(e) => setFormData({ ...formData, sector: e.target.value })}
                  />
                </div>
                <div>
                  <label className="block text-[11px] font-black text-black uppercase mb-1.5 ml-1">Ramal</label>
                  <input
                    type="text"
                    required
                    readOnly={isEditing && !isAdmin}
                    className={`w-full px-4 py-3 rounded-xl border-2 border-slate-100 bg-slate-50 text-black font-bold outline-none focus:ring-2 focus:ring-blue-500 ${isEditing && !isAdmin ? 'opacity-70' : ''}`}
                    value={formData.extension}
                    onChange={(e) => setFormData({ ...formData, extension: e.target.value })}
                  />
                </div>
              </div>

              <div>
                <label className="block text-[11px] font-black text-black uppercase mb-1.5 ml-1">Causa / Descrição</label>
                <textarea
                  required
                  rows={4}
                  readOnly={isEditing && !isAdmin}
                  className={`w-full px-4 py-3 rounded-xl border-2 border-slate-100 bg-slate-50 text-black font-bold outline-none focus:ring-2 focus:ring-blue-500 resize-none ${isEditing && !isAdmin ? 'opacity-70' : ''}`}
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                ></textarea>
              </div>

              {/* Status control for Admin */}
              {isAdmin && isEditing && (
