import React, { useState, useMemo } from 'react';
import { Ticket, TicketStatus } from '../types';

interface ReportModalProps {
  tickets: Ticket[];
  onClose: () => void;
}

const ReportModal: React.FC<ReportModalProps> = ({ tickets, onClose }) => {
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [hasGenerated, setHasGenerated] = useState(false);

  const reportData = useMemo(() => {
    if (!startDate || !endDate) return null;

    const start = new Date(startDate);
    start.setHours(0, 0, 0, 0);
    const end = new Date(endDate);
    end.setHours(23, 59, 59, 999);

    const filtered = tickets.filter(t => {
      const created = new Date(t.createdAt);
      return created >= start && created <= end;
    });

    const breakdown = {
      [TicketStatus.OPEN]: filtered.filter(t => t.status === TicketStatus.OPEN).length,
      [TicketStatus.ANALYSIS]: filtered.filter(t => t.status === TicketStatus.ANALYSIS).length,
      [TicketStatus.WAITING]: filtered.filter(t => t.status === TicketStatus.WAITING).length,
      [TicketStatus.CLOSED]: filtered.filter(t => t.status === TicketStatus.CLOSED).length,
    };

    return {
      total: filtered.length,
      breakdown
    };
  }, [tickets, startDate, endDate]);

  const handleGenerate = (e: React.FormEvent) => {
    e.preventDefault();
    setHasGenerated(true);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
      <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden flex flex-col border border-slate-200">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
          <h3 className="text-xl font-black text-slate-900 tracking-tight flex items-center gap-2">
            <i className="fas fa-chart-bar text-blue-600"></i>
            Extrair Relatório
          </h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-900 transition-colors">
            <i className="fas fa-times text-xl"></i>
          </button>
        </div>

        <div className="p-8 space-y-8">
          <form onSubmit={handleGenerate} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-white">
                <label className="block text-[11px] font-black text-black uppercase mb-1.5 ml-1">Data Inicial</label>
                <input
                  type="date"
                  required
                  className="w-full px-4 py-3 border-2 border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold text-sm bg-slate-50 focus:bg-white transition-all"
                  value={startDate}
                  onChange={(e) => {
                    setStartDate(e.target.value);
                    setHasGenerated(false);
                  }}
                />
              </div>
              <div className="bg-white">
                <label className="block text-[11px] font-black text-black uppercase mb-1.5 ml-1">Data Final</label>
                <input
                  type="date"
                  required
                  className="w-full px-4 py-3 border-2 border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 font-bold text-sm bg-slate-50 focus:bg-white transition-all"
                  value={endDate}
                  onChange={(e) => {
                    setEndDate(e.target.value);
                    setHasGenerated(false);
                  }}
                />
              </div>
            </div>
            <button
              type="submit"
              className="w-full py-4 bg-slate-900 text-white font-black rounded-2xl hover:bg-black transition-all shadow-lg text-[11px] uppercase tracking-widest mt-2"
            >
              PROCESSAR RELATÓRIO
            </button>
          </form>

          {hasGenerated && reportData && (
            <div className="space-y-5 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="p-6 bg-slate-900 rounded-[2rem] text-center border-4 border-white shadow-2xl">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">Volume Total</p>
                <p className="text-5xl font-black text-white mt-1">{reportData.total}</p>
              </div>

              <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 space-y-3">
                <ReportRow label="Em Aberto" count={reportData.breakdown[TicketStatus.OPEN]} color="text-blue-600" bg="bg-blue-100" />
                <ReportRow label="Em Análise" count={reportData.breakdown[TicketStatus.ANALYSIS]} color="text-purple-600" bg="bg-purple-100" />
                <ReportRow label="Em Espera" count={reportData.breakdown[TicketStatus.WAITING]} color="text-amber-600" bg="bg-amber-100" />
                <ReportRow label="Encerrados" count={reportData.breakdown[TicketStatus.CLOSED]} color="text-emerald-600" bg="bg-emerald-100" />
              </div>

              <button
                onClick={() => window.print()}
                className="w-full py-3 bg-white border-2 border-slate-200 text-slate-900 font-black rounded-xl text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all"
              >
                <i className="fas fa-print mr-2"></i>Imprimir em PDF
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

